设置全屏 123456789101112void full_screen(){ HWND hwnd = GetForegroundWindow(); int cx = GetSystemMetrics(SM_CXSCREEN); /* 屏幕宽度 像素 */ int cy = GetSystemMetrics(SM_CYSCREEN); /* 屏幕高度 像素 */ LONG l_WinStyle = GetWindowLong(hwnd,GWL_STYLE); /* 获取窗口信息 */ /* 设置窗口信息 最大化 取消标题栏及边框 */ SetWindowLong(hwnd,GWL_STYLE,(l_WinStyle | WS_POPUP | WS_MAXIMIZE) &amp; ~WS_CAPTION &amp; ~WS_THICKFRAME &amp; ~WS_BORDER); SetWindowPos(hwnd, HWND_TOP, 0, 0, cx, cy, 0);} 获取字体大小12345678910111213141516171819202122COORD get_font_size(){ COORD font_size; HANDLE handle = GetStdHandle(STD_OUTPUT_HANDLE); /* 字体信息 */ struct CONSOLE_FONT { DWORD index; COORD dim; } cfi; typedef COORD (WINAPI *PROCGETCONSOLEFONTSIZE)(HANDLE, DWORD); typedef BOOL (WINAPI *PROCGETCURRENTCONSOLEFONT)(HANDLE, BOOL, struct CONSOLE_FONT*); HMODULE hKernel32 = GetModuleHandle(&quot;kernel32&quot;); PROCGETCONSOLEFONTSIZE GetConsoleFontSize = (PROCGETCONSOLEFONTSIZE)GetProcAddress(hKernel32,&quot;GetConsoleFontSize&quot;); PROCGETCURRENTCONSOLEFONT GetCurrentConsoleFont = (PROCGETCURRENTCONSOLEFONT)GetProcAddress(hKernel32,&quot;GetCurrentConsoleFont&quot;); GetCurrentConsoleFont(handle, FALSE, &amp;cfi); /* 获取当前字体索引信息 */ font_size = GetConsoleFontSize(handle, cfi.index); /* 获取当前字体宽高信息[字符宽度及高度所占像素数] */ return font_size;} 获取窗口大小(单位：像素)12345678COORD get_screen_size(){ HWND hwnd = GetForegroundWindow(); COORD size; size.cx = GetSystemMetrics(SM_CXSCREEN); /* 屏幕宽度 */ size.cy = GetSystemMetrics(SM_CYSCREEN); /* 屏幕高度 */ return size;} 获取窗口大小(单位：字符)(依赖于get_font_size())1234567891011121314COORD get_screen_size(){ HWND hwnd = GetForegroundWindow(); HANDLE handle = GetStdHandle(STD_OUTPUT_HANDLE); /* 标准输出缓冲区句柄 */ int cx = GetSystemMetrics(SM_CXSCREEN); /* 屏幕宽度 */ int cy = GetSystemMetrics(SM_CYSCREEN); /* 屏幕高度 */ COORD size = get_font_size(); char cmd[32] = { 0 }; size.X=cx/size.X, size.Y=cy/size.Y; return size;} 设置颜色1234567void SetColor(int fore=7,int back=0){ unsigned char m_color = fore; m_color += (back &lt;&lt; 4); SetConsoleTextAttribute(GetStdHandle(STD_OUTPUT_HANDLE), m_color); return;} 隐藏光标1234void HideCursor(){ CONSOLE_CURSOR_INFO cursor_info={1,0}; SetConsoleCursorInfo(GetStdHandle(STD_OUTPUT_HANDLE),&amp;cursor_info);} 光标移动1234567void GoToxy(int x,int y){ COORD coord; coord.X=y;//这里调换了顺序，否则就是将输出指针移到y行，x列 coord.Y=x; HANDLE a=GetStdHandle(STD_OUTPUT_HANDLE); SetConsoleCursorPosition(a,coord);} 缓慢输出12345678void slowout(char *p){ while(1){ if(*p!=0) printf(&quot;%c&quot;,*p++); else break; Sleep(20); } Sleep(500);} 键盘、鼠标检测初始化1#define KEY_DOWN(VK_NONAME) ((GetAsyncKeyState(VK_NONAME) &amp; 0x8000) ? 1:0) 键符对照123456789101112131415161718192021222324252627282930313233343536373839404142434445常量名 对应按键 取值—————————————————————————————————————————————————————————VK_LBUTTON 鼠标左键 0x01VK_RBUTTON 鼠标右键 0x02VK_CANCEL Ctrl + Break 0x03VK_MBUTTON 鼠标中键 0x04VK_BACK Backspace 键 0x08VK_TAB Tab 键 0x09VK_RETURN 回车键 0x0DVK_SHIFT Shift 键 0x10VK_CONTROL Ctrl 键 0x11VK_MENU Alt 键 0x12VK_PAUSE Pause 键 0x13VK_CAPITAL Caps Lock 键 0x14VK_ESCAPE Esc 键 0x1BVK_SPACE 空格键 0x20VK_PRIOR Page Up 键 0x21VK_NEXT Page Down 键 0x22VK_END End 键 0x23VK_HOME Home 键 0x24VK_LEFT 左箭头键 0x25VK_UP 上箭头键 0x26VK_RIGHT 右箭头键 0x27VK_DOWN 下箭头键 0x28VK_SNAPSHOT Print Screen 键 0x2CVK_Insert Insert 键 0x2DVK_Delete Delete 键 0x2E'0' – '9' 数字 0 - 9 0x30 - 0x39'A' – 'Z' 字母 A - Z 0x41 - 0x5AVK_LWIN 左WinKey(104键盘才有) 0x5BVK_RWIN 右WinKey(104键盘才有) 0x5CVK_APPS AppsKey(104键盘才有) 0x5DVK_NUMPAD0 小键盘 0 键 0x60VK_NUMPAD1 小键盘 1 键 0x61VK_NUMPAD2 小键盘 2 键 0x62VK_NUMPAD3 小键盘 3 键 0x63VK_NUMPAD4 小键盘 4 键 0x64VK_NUMPAD5 小键盘 5 键 0x65VK_NUMPAD6 小键盘 6 键 0x66VK_NUMPAD7 小键盘 7 键 0x67VK_NUMPAD8 小键盘 8 键 0x68VK_NUMPAD9 小键盘 9 键 0x69VK_F1 - VK_F24 功能键F1 – F24 0x70 - 0x87VK_NUMLOCK Num Lock 键 0x90VK_SCROLL Scroll Lock 键 0x91 检测鼠标按下1234567891011121314151617181920212223while (1){ if (KEY_DOWN(MOUSE_MOVED)){//判断左键 printf(&quot;你按了鼠标左键&quot;); } else{ printf(&quot;你没按鼠标左键&quot;); } printf(&quot;
&quot;); if (KEY_DOWN(MOUSE_EVENT)){//判断右键 printf(&quot;你按了鼠标右键&quot;); } else{ printf(&quot;你没按鼠标右键&quot;); } printf(&quot;
&quot;); if (KEY_DOWN(MOUSE_WHEELED)){//判断滚轮 printf(&quot;你按了鼠标滚轮&quot;); } else{ printf(&quot;你没按鼠标滚轮&quot;); } system(&quot;cls&quot;);} 检测鼠标位置123POINT p;GetCursorPos(&amp;p);printf(&quot;(%d,%d)
&quot;,p.x,p.y); 多线程1234567#include&lt;iostream&gt;#include&lt;thread&gt;using namespace std;int main(){ thread th1(...);//第一个参数为函数名，第二个参数为该函数的第一个参数，如果该函数接收多个参数就依次写在后面。此时线程开始执行。 thread th2(...);//第一个参数为函数名，第二个参数为该函数的第一个参数，如果该函数接收多个参数就依次写在后面。此时线程开始执行。}
